#include <iostream>

int main() {
    int x {};
    int y {};
    std::cin >> x >> y;

    std::cout << "outer x: " << x << '\n';
    std::cout << "outer y: " << y << '\n';

    {
        int sum { x + y };
        std::cout << "block sum: " << sum << '\n';
    }

    std::cout << "outer x after block: " << x << '\n';

    return 0;
}

