solution_code:
#include <iostream>

int main() {
    int a {};
    int b {};
    std::cin >> a >> b;

    std::cout << "outer a = " << a << '\n';

    {
        int saved_a { a };
        int a { saved_a * 2 };
        std::cout << "inner a = " << a << '\n';
        std::cout << "inner b = " << b << '\n';
    }

    std::cout << "back to outer a = " << a << '\n';

    return 0;
}
